import React, { useState } from 'react';

const Contact = () => {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = 'Name is required.';
    if (!form.email.trim()) e.email = 'Email is required.';
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = 'Enter a valid email.';
    if (!form.message.trim()) e.message = 'Message cannot be empty.';
    return e;
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: '' });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) { setErrors(errs); return; }
    setSubmitted(true);
  };

  const inputStyle = {
    width: '100%',
    background: 'rgba(0,55,145,0.15)',
    border: '1px solid rgba(0,112,204,0.35)',
    borderRadius: '6px',
    padding: '10px 12px',
    fontSize: '13px',
    color: '#ffffff',
    fontFamily: 'inherit',
    outline: 'none',
  };

  const socialLinks = [
    { href: 'https://github.com/amd-16', img: '/images/github-logo.png', alt: 'GitHub', sym: '✕', color: '#7fc5e8' },
    { href: 'https://mail.google.com/mail/', img: '/images/gmail-logo.png', alt: 'Gmail', sym: '□', color: '#e87bce' },
    { href: 'https://www.facebook.com/alihakim.dimacaling15', img: '/images/facebook-logo.png', alt: 'Facebook', sym: '○', color: '#e87b7b' },

  ];

  return (
    <footer
      id="Contact"
      className="text-center pt-12 pb-10 px-4"
      style={{
        background: 'linear-gradient(180deg, #0a0f2e 0%, #00052b 100%)',
        borderTop: '1px solid rgba(0,112,204,0.3)',
      }}
    >
      {/* PS symbols divider */}
      <p className="text-xs mb-6 tracking-widest" style={{ color: 'rgba(255,255,255,0.2)', letterSpacing: '6px' }}>
        ✕&nbsp;&nbsp;○&nbsp;&nbsp;□&nbsp;&nbsp;△
      </p>

      <h5
        className="italic font-bold mb-6 text-sm tracking-widest"
        style={{ color: '#7fc5e8', fontFamily: "'Orbitron', sans-serif", letterSpacing: '3px' }}
      >
        MY LINKS
      </h5>

      {/* Social icons */}
      <div id="social-links" className="flex justify-center items-center gap-6 mt-2 mb-10">
        {socialLinks.map(({ href, img, alt, sym, color }) => (
          <a
            key={alt}
            href={href}
            target="_blank"
            rel="noreferrer"
            className="transition-transform duration-300 hover:scale-110 inline-flex flex-col items-center gap-1"
          >
            <span style={{ color, fontSize: '11px' }}>{sym}</span>
            <img src={img} alt={alt} width="46" height="46" style={{ filter: 'brightness(1.1)' }} />
          </a>
        ))}
      </div>

      {/* Contact form */}
      <div className="max-w-md mx-auto text-left">
        <h5
          className="font-bold mb-5 text-center text-sm tracking-widest"
          style={{ color: '#7be8b4', letterSpacing: '2px' }}
        >
          △ SEND A MESSAGE
        </h5>

        {submitted ? (
          <p className="text-center font-semibold" style={{ color: '#7be8b4' }}>
            Thanks, {form.name}! Your message has been sent.
          </p>
        ) : (
          <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <div>
              <input
                type="text"
                name="name"
                placeholder="Your name"
                value={form.name}
                onChange={handleChange}
                style={inputStyle}
              />
              {errors.name && <p className="text-xs mt-1" style={{ color: '#e87b7b' }}>{errors.name}</p>}
            </div>
            <div>
              <input
                type="text"
                name="email"
                placeholder="Your email"
                value={form.email}
                onChange={handleChange}
                style={inputStyle}
              />
              {errors.email && <p className="text-xs mt-1" style={{ color: '#e87b7b' }}>{errors.email}</p>}
            </div>
            <div>
              <textarea
                name="message"
                placeholder="Your message"
                value={form.message}
                onChange={handleChange}
                rows={4}
                style={{ ...inputStyle, resize: 'none' }}
              />
              {errors.message && <p className="text-xs mt-1" style={{ color: '#e87b7b' }}>{errors.message}</p>}
            </div>
            <button
              type="submit"
              className="py-2 rounded font-bold text-sm transition hover:opacity-90"
              style={{
                background: 'linear-gradient(90deg, #003791, #0070cc)',
                color: '#ffffff',
                border: 'none',
                cursor: 'pointer',
                fontFamily: 'inherit',
                letterSpacing: '2px',
              }}
            >
              ✕ SEND
            </button>
          </form>
        )}
      </div>

      <p className="text-xs mt-10" style={{ color: 'rgba(255,255,255,0.15)', letterSpacing: '2px' }}>
        © {new Date().getFullYear()} ALIHAKIM M. DIMACALING
      </p>
    </footer>
  );
};

export default Contact;
